1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	function calculateComponentPremium(items: any[]): number {
16	  const counts: Record<string, number> = {};
17	  for (const item of items) {
18	    if (COMPONENT_TYPES.has(item.type)) {
19	      counts[item.type] = (counts[item.type] ?? 0) + 1;
20	    }
21	  }
22	  let premium = 0;
23	  for (const count of Object.values(counts)) {
24	    if (count === BLOCK_SIZE) {
25	      premium += BLOCK_PREMIUM;
26	    } else {
27	      premium += count * COMPONENT_PREMIUM;
28	    }
29	  }
30	  return premium;
31	}
32	
33	function calculateItemPremium(item: any): number {
34	  if (COMPONENT_TYPES.has(item.type)) {
35	    return 0;
36	  }
37	  const base = BASE_PREMIUMS[item.type] ?? 0;
38	  let premium = base;
39	  if (item.cursed) {
40	    premium += base * 0.5;
41	  }
42	  if (item.enchantment >= 5) {
43	    premium += base * 0.3;
44	  }
45	  return premium;
46	}
47	
48	function calculateNonComponentBasePremium(items: any[]): number {
49	  return items
50	    .filter((item: any) => !COMPONENT_TYPES.has(item.type))
51	    .reduce((sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
52	}
53	
54	function calculateQuotePremium(items: any[], customer: any): number {
55	  const itemTotal = items.reduce((sum, item) => sum + calculateItemPremium(item), 0);
56	  const componentTotal = calculateComponentPremium(items);
57	  const policyBase = calculateNonComponentBasePremium(items) + componentTotal;
58	  const firstInsurance = policyBase * 0.1;
59	  const loyalty = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
60	  return Math.ceil(PROCESSING_FEE + itemTotal + componentTotal + firstInsurance - loyalty);
61	}
62	
63	export function processScenario(scenario: any): any {
64	  const results = scenario.steps.map((step: any) => {
65	    if (step.op === "quote") {
66	      return { premium: calculateQuotePremium(step.items, scenario.customer) };
67	    }
68	  });
69	  return { results };
70	}
